const payload = $json.body || $json;
const metadata = payload.routing || {};
const preferred = String(metadata.preferredDestination || payload.delivery || '').toLowerCase();
const destination = preferred || $('Workflow Parameters').first().json.defaultDestination;
return [{ json: {
  accountName: payload.accountName || payload.account || 'Unknown Account',
  audience: payload.audience || 'internal-team',
  destination,
  rawPayload: payload,
  fallbackWebhookUrl: $('Workflow Parameters').first().json.fallbackWebhookUrl
} }];

